    60→        `//*[text()='${text}']`,
    61→        element,
    62→        null,
    63→        XPathResult.ORDERED_NODE_ITERATOR_TYPE,
    64→        null
    65→    );
    66→    const result: Element[] = [];
    67→    let match = null;
    68→
    69→    while ((match = xpathResult?.iterateNext())) {
    70→        result.push(match as Element);
    71→    }
    72→    return result;
    73→};
