   102→const moveNodesToBlockquote = (nodes: Node[], blockquote: Element): void => {
   103→    nodes.forEach((node) => {
   104→        node.parentNode?.removeChild(node);
   105→        blockquote.appendChild(node);
   106→    });
   107→};
