   109→const processMicrosoftWordEmail = (inputDocument: Element): Element => {
   110→    const wordSection = inputDocument.querySelector('div.WordSection1');
   111→
   112→    if (!wordSection) {
   113→        return inputDocument;
   114→    }
   115→
   116→    const existingSeparator = inputDocument.querySelector(BLOCKQUOTE_SELECTOR);
   117→    if (existingSeparator) {
   118→        return inputDocument;
   119→    }
   120→
   121→    const separatorDiv = Array.from(wordSection.querySelectorAll('div')).find(hasMicrosoftWordSeparatorStyle);
   122→
   123→    if (!separatorDiv) {
   124→        return inputDocument;
   125→    }
   126→
   127→    const blockquote = inputDocument.ownerDocument?.createElement('blockquote');
   128→    if (!blockquote) {
   129→        return inputDocument;
   130→    }
