   133→
   134→    const elementsToMove = collectSiblingNodesAfter(separatorDiv);
   135→    moveNodesToBlockquote(elementsToMove, blockquote);
   136→
   137→    wordSection.appendChild(blockquote);
   138→
   139→    return inputDocument;
   140→};
