   144→ * Return the HTML content split at the blockquote start
   145→ */
   146→export const locateBlockquote = (inputDocument: Element | undefined): [content: string, blockquote: string] => {
   147→    if (!inputDocument) {
   148→        return ['', ''];
   149→    }
   150→
   151→    // Process Microsoft Word emails first to transform them into standard blockquote structure
   152→    const processedDocument = processMicrosoftWordEmail(inputDocument);
   153→    const body = processedDocument.querySelector('body');
   154→    const tmpDocument = body || processedDocument;
   155→
   156→    const parentHTML = tmpDocument.innerHTML || '';
   157→    let result: [string, string] | null = null;
   158→
   159→    const testBlockquote = (blockquote: Element) => {
   160→        const blockquoteHTML = blockquote.outerHTML || '';
   161→        const [beforeHTML = '', afterHTML = ''] = split(parentHTML, blockquoteHTML);
   162→
   163→        const after = parseStringToDOM(afterHTML);
   164→
   165→        // The "real" blockquote will be determined based on the fact:
   166→        // - That there is no text after the current blockquote element
   167→        // - That there is no "important" element after the current blockquote element
   168→        const hasImageAfter = after.body.querySelector(ELEMENTS_AFTER_BLOCKQUOTES.join(','));
   169→        const hasTextAfter = after.body?.textContent?.trim().length;
   170→
   171→        if (!hasImageAfter && !hasTextAfter) {
   172→            return [beforeHTML, blockquoteHTML] as [string, string];
   173→        }
   174→
   175→        return null;
   176→    };
   177→
   178→    // Standard search with a composed query selector
   179→    const blockquotes = [...tmpDocument.querySelectorAll(BLOCKQUOTE_SELECTOR)];
   180→    blockquotes.forEach((blockquote) => {
   181→        if (result === null) {
   182→            result = testBlockquote(blockquote);
   183→        }
   184→    });
   185→
   186→    // Second search based on text content with xpath
   187→    if (result === null) {
   188→        BLOCKQUOTE_TEXT_SELECTORS.forEach((text) => {
   189→            if (result === null) {
   190→                searchForContent(tmpDocument, text).forEach((blockquote) => {
   191→                    if (result === null) {
   192→                        result = testBlockquote(blockquote);
   193→                    }
   194→                });
   195→            }
   196→        });
   197→        // document.ownerDocument?.evaluate;
   198→    }
   199→
   200→    return result || [parentHTML, ''];
   201→};
