   203→export const removeSignatureFromHTMLMessage = (contentBeforeBlockquote: string): string => {
   204→    const contentDocument = parseStringToDOM(contentBeforeBlockquote);
   205→    contentDocument.body.querySelector('.protonmail_signature_block')?.remove();
   206→    return contentDocument.body.outerHTML;
   207→};
